import anthropic

client = anthropic.Anthropic()


class QuotaExhaustedError(Exception):
    """Raised when the monthly quota has been exhausted."""


def call_quota_aware(prompt: str) -> str:
    try:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=256,
            messages=[{"role": "user", "content": prompt}],
        )
        return resp.content[0].text
    except anthropic.RateLimitError as e:
        # Distinguish between transient rate limit (retryable)
        # and quota exhaustion (not retryable until next period).
        # Anthropic returns a specific error message when the monthly spend cap
        # has been reached.
        msg = str(e).lower()
        if "spend limit" in msg or "quota" in msg or "monthly" in msg:
            raise QuotaExhaustedError(
                "Monthly API quota exhausted. Increase your limit at console.anthropic.com."
            ) from e
        # Regular rate limit — let the caller retry with backoff
        raise


try:
    text = call_quota_aware("Hello!")
    print(text)
except QuotaExhaustedError as e:
    print(f"Service unavailable: {e}")
    # Log, send alert, show maintenance page, etc.
